import os
import tempfile
import base64
import json
import hashlib

class Substrato631OpenServGateway:
    def __init__(self):
        self.data = {
            "id": "631-OPENSERV-GATEWAY",
            "name": "OpenServ Gateway Attestation and Lightweight Verification",
            "status": "CANONIZED_CLEAN",
            "incorporation_date": "2026-05-28"
        }

        self.files_b64 = {
            "core_kernel/Cargo.toml": "",
            "core_kernel/src/main.rs": "",
            "python_gateway/gateway.py": "",
            "python_gateway/requirements.txt": "ZmFzdGFwaQp1dmljb3JuCnB5ZGFudGljCmVkMjU1MTkK",
            "rust_gateway/Cargo.toml": "",
            "rust_gateway/src/main.rs": "",
        }

    def generate(self):
        temp_dir = tempfile.mkdtemp()
        for filename, b64_content in self.files_b64.items():
            path = os.path.join(temp_dir, filename)
            os.makedirs(os.path.dirname(path), exist_ok=True)
            content = base64.b64decode(b64_content)
            with os.fdopen(os.open(path, os.O_WRONLY | os.O_CREAT, 0o644), "wb") as f:
                f.write(content)

        canonical_str = json.dumps(self.data, sort_keys=True)
        calculated_seal = hashlib.sha3_256(canonical_str.encode("utf-8")).hexdigest()
        self.data["canonical_seal"] = calculated_seal

        fd, report_path = tempfile.mkstemp(suffix=".json")
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            json.dump(self.data, f, indent=4, ensure_ascii=False)

        return temp_dir, report_path

if __name__ == "__main__":
    canonizer = Substrato631OpenServGateway()
    temp_dir, report_path = canonizer.generate()
    print("Canonized 631-OPENSERV-GATEWAY into directory: " + temp_dir)
    print("Canonical JSON report: " + report_path)
